      "screenName": "Womens Collection",
      "html": "<head>
<style id="base-styles">
  * { box-sizing: border-box; }
  body {
    margin: 0;
    padding: 0;
    font-family: var(--font-family-body, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif);
    color: var(--foreground);
    background-color: var(--background);
    line-height: 1.5;
    -webkit-font-smoothing: antialiased;
  }
  a { text-decoration: none; color: inherit; }
  img { max-width: 100%; display: block; }
</style>

<style id="header-styles">
  .announcement-bar {
    background-color: var(--foreground);
    color: var(--background);
    text-align: center;
    padding: 10px 16px;
    font-size: 11px;
    letter-spacing: 0.15em;
    text-transform: uppercase;
    font-weight: 500;
  }
  .header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 24px 40px;
    background-color: var(--background);
    border-bottom: 1px solid var(--border);
    position: sticky;
    top: 0;
    z-index: 100;
  }
  .nav-left, .nav-right {
    display: flex;
    align-items: center;
    gap: 32px;
    flex: 1;
  }
  .nav-right {
    justify-content: flex-end;
  }
  .logo {
    flex: 0 0 auto;
    display: flex;
    justify-content: center;
  }
  .logo img {
    height: 32px;
    width: auto;
    object-fit: contain;
  }
  .nav-link {
    font-size: 13px;
    text-transform: uppercase;
    letter-spacing: 0.12em;
    font-weight: 500;
  }
  .icon-link {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 24px;
    height: 24px;
    color: var(--foreground);
  }
</style>

<style id="collection-styles">
  .collection-header {
    text-align: center;
    padding: 80px 40px 40px;
    background-color: var(--background);
  }
  .collection-title {
    font-size: 40px;
    font-weight: 400;
    letter-spacing: 0.05em;
    margin: 0 0 16px 0;
    text-transform: uppercase;
  }
  .collection-desc {
    max-width: 600px;
    margin: 0 auto;
    font-size: 15px;
    color: var(--muted-foreground);
    line-height: 1.6;
  }
  .collection-main {
    padding: 0 40px 100px;
  }
  .container {
    max-width: 1400px;
    margin: 0 auto;
  }
  .collection-toolbar {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 24px 0;
    margin-bottom: 40px;
    border-bottom: 1px solid var(--border);
  }
  .toolbar-group {
    display: flex;
    align-items: center;
    flex: 1;
  }
  .toolbar-group.center {
    justify-content: center;
  }
  .toolbar-group.right {
    justify-content: flex-end;
  }
  .toolbar-btn {
    background: none;
    border: none;
    font-family: inherit;
    font-size: 12px;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    font-weight: 500;
    color: var(--foreground);
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 0;
  }
  .product-count {
    font-size: 12px;
    color: var(--muted-foreground);
    text-transform: uppercase;
    letter-spacing: 0.1em;
  }
  .product-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 40px 32px;
  }
  .product-card {
    position: relative;
  }
  .product-image {
    position: relative;
    width: 100%;
    aspect-ratio: 3/4;
    background-color: var(--muted);
    margin-bottom: 20px;
    overflow: hidden;
  }
  .product-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }
  .product-badge {
    position: absolute;
    top: 12px;
    left: 12px;
    background-color: var(--foreground);
    color: var(--background);
    font-size: 10px;
    padding: 4px 10px;
    text-transform: uppercase;
    letter-spacing: 0.15em;
    font-weight: 500;
    z-index: 10;
  }
  .product-info {
    text-align: center;
  }
  .product-title {
    font-size: 13px;
    font-weight: 500;
    margin: 0 0 8px 0;
    letter-spacing: 0.05em;
  }
  .product-price {
    font-size: 13px;
    color: var(--muted-foreground);
    margin: 0;
  }
  .pagination {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 16px;
    margin-top: 80px;
  }
  .page-link {
    font-size: 13px;
    color: var(--muted-foreground);
    padding: 8px;
  }
  .page-link.active {
    color: var(--foreground);
    border-bottom: 1px solid var(--foreground);
  }
</style>

<style id="footer-styles">
  .footer {
    background-color: var(--background);
    border-top: 1px solid var(--border);
    padding: 100px 40px 40px;
  }
  .footer-top {
    display: grid;
    grid-template-columns: 1.5fr 1fr 1.5fr;
    gap: 80px;
    max-width: 1400px;
    margin: 0 auto;
  }
  .footer-heading {
    font-size: 13px;
    text-transform: uppercase;
    letter-spacing: 0.15em;
    font-weight: 500;
    margin: 0 0 32px 0;
  }
  .footer-text {
    font-size: 14px;
    color: var(--muted-foreground);
    line-height: 1.7;
    margin: 0 0 16px 0;
  }
  .footer-links {
    list-style: none;
    padding: 0;
    margin: 0;
  }
  .footer-links li {
    margin-bottom: 16px;
  }
  .footer-links a {
    font-size: 14px;
    color: var(--muted-foreground);
  }
  .newsletter-form .input-wrapper {
    display: flex;
    border-bottom: 1px solid var(--border);
    padding-bottom: 12px;
    margin-top: 32px;
  }
  .newsletter-form input {
    flex: 1;
    border: none;
    background: transparent;
    font-size: 14px;
    outline: none;
    color: var(--foreground);
    padding: 0;
  }
  .newsletter-form .btn-submit {
    background: none;
    border: none;
    font-size: 12px;
    font-weight: 500;
    letter-spacing: 0.1em;
    cursor: pointer;
    padding: 0;
    color: var(--foreground);
    text-transform: uppercase;
  }
  .footer-bottom {
    max-width: 1400px;
    margin: 100px auto 0;
    text-align: center;
    font-size: 13px;
    color: var(--muted-foreground);
    border-top: 1px solid var(--border);
    padding-top: 32px;
  }
</style>

</head><body><div class="prestige-theme">
